let pendingImg={p:null,r:null};
function previewImg(e,prefix){const file=e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=function(ev){const wrap=document.getElementById(prefix+'img-wrap');wrap.innerHTML='<img class="img-preview" id="'+prefix+'img-prev" src="'+ev.target.result+'"><div class="img-actions"><button type="button" class="btn btn-sm btn-o" onclick="event.stopPropagation();clearImg(\''+prefix+'\')">Remove</button><span class="hint">Click to replace</span></div><input type="file" accept="image/*" onchange="previewImg(event,\''+prefix+'\')">';pendingImg[prefix]=ev.target.result};reader.readAsDataURL(file)}
function clearImg(prefix){const wrap=document.getElementById(prefix+'img-wrap');wrap.innerHTML='<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg><span>Click or drag to upload</span><span class="hint">JPG, PNG — 1200×800px</span><input type="file" accept="image/*" onchange="previewImg(event,\''+prefix+'\')">';pendingImg[prefix]=null}
