/* AUTH */
let CU=null;
function openLogin(){document.getElementById('loginmod').classList.add('open')}
function closeLogin(){document.getElementById('loginmod').classList.remove('open');document.getElementById('lerr').textContent=''}
function doLogin(){const e=document.getElementById('le').value.trim(),p=document.getElementById('lp').value;if(!e||!p){document.getElementById('lerr').textContent='Fill all fields';return}const a=ACCS.find(x=>x.email===e&&x.pass===p);if(!a){document.getElementById('lerr').textContent='Invalid credentials';return}CU=a;closeLogin();if(a.role==='admin'){showPage('admin');renderAdmin()}else{showPage('user');renderUser()}updateNav()}
function doLogout(){CU=null;showPage('public');updateNav()}
function showPage(p){document.querySelectorAll('.page').forEach(el=>el.classList.remove('active'));document.getElementById('pg-'+p).classList.add('active');window.scrollTo(0,0)}
function goPublic(){showPage('public');window.scrollTo(0,0)}

function updateNav(){
  const r=document.getElementById('navr');
  if(!CU){r.innerHTML='<a onclick="scrollTo2(\'#features\')">App</a><a onclick="scrollTo2(\'#workshops\')">Workshops</a><a onclick="scrollTo2(\'#kits\')">Kits</a><a onclick="scrollTo2(\'#subscribe\')">Subscribe</a><button class="nbtn" onclick="openLogin()">Log in</button>';return}
  if(CU.role==='admin')r.innerHTML='<a onclick="goPublic()">Website</a><a onclick="showPage(\'admin\');renderAdmin()">Admin</a><div class="nu" onclick="showPage(\'admin\');renderAdmin()"><div class="nuav">'+CU.avatar+'</div><span style="font-size:12px;font-weight:500">Admin</span></div>';
  else r.innerHTML='<a onclick="goPublic()">Home</a><a onclick="scrollTo2(\'#workshops\')">Workshops</a><a onclick="scrollTo2(\'#kits\')">Kits</a><div class="nu" onclick="showPage(\'user\');renderUser()"><div class="nuav">'+CU.avatar+'</div><span style="font-size:12px;font-weight:500">'+CU.name.split(' ')[0]+'</span></div>';
}

/* PUBLIC WORKSHOPS */
let wsBook='';
function renderPublicWS(){document.getElementById('ws-grid').innerHTML=workshops.map(w=>'<div class="wc"><div class="ws-img"><svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg><span>Workshop image</span></div><div class="whd"><div class="wd3">'+w.date+'</div><div class="ws3">'+w.spots+' spots left</div></div><div class="wbd"><h3>'+w.name+'</h3><p>'+w.desc+'</p><div style="display:flex;justify-content:space-between;align-items:center"><div class="wpd">'+w.price+' <span>/ person</span></div><button class="btn btn-sm" onclick="bookOrEnrol(\''+w.name+'\')">Book now</button></div></div></div>').join('')}
function bookOrEnrol(n){if(CU&&CU.role==='user'){if(!CU.workshops)CU.workshops=[];if(!CU.workshops.includes(n)){CU.workshops.push(n);toast('Enrolled in '+n+'!')}else{toast('Already enrolled!')}return}bookWSOpen(n)}
function bookWSOpen(n){wsBook=n;document.getElementById('wsmodtitle').textContent=n;document.getElementById('wsmod').classList.add('open')}
function bookWS(){const n=document.getElementById('ws-name').value,e=document.getElementById('ws-email').value;if(!n||!e){document.getElementById('wserr').textContent='Fill all fields';return}document.getElementById('wsmod').classList.remove('open');toast('Spot reserved for '+wsBook+'! Check your email.')}
document.getElementById('wsmod').addEventListener('click',function(e){if(e.target===this)this.classList.remove('open')});
renderPublicWS();

/* USER */
let uTab='profile';
function renderUser(){if(!CU)return;document.getElementById('u-av').textContent=CU.avatar;document.getElementById('u-nm').textContent=CU.name;document.getElementById('u-em').textContent=CU.email;
document.getElementById('utabs').innerHTML=[{id:'profile',l:'Profile & Subscription'},{id:'workshops',l:'Workshops'},{id:'recipes',l:'Saved Recipes'}].map(t=>'<button class="'+(t.id===uTab?'act':'')+'" onclick="uTab=\''+t.id+'\';renderUser()">'+t.l+'</button>').join('');
const c=document.getElementById('ucont');
if(uTab==='profile'){c.innerHTML='<div class="sub-active"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px"><div style="font-size:16px;font-weight:500">'+(CU.plan||'Free')+' Plan</div><span class="tag t-ac">Active</span></div><div style="font-size:13px;color:var(--t2)">Member since '+(CU.joined||'recently')+'</div></div><div class="tc"><div class="s2"><span>Payment history</span></div>'+(CU.payments||[]).map(p=>'<div class="pr2"><span>'+p.d+'</span><span>'+p.t+'</span><span style="font-weight:500">'+p.a+'</span></div>').join('')+(!(CU.payments||[]).length?'<div class="empty">No payments yet</div>':'')+'</div><div class="tc"><div class="s2"><span>Account</span></div><div class="fg"><label>Name</label><input value="'+CU.name+'"></div><div class="fg"><label>Email</label><input value="'+CU.email+'"></div><div style="margin-top:12px"><button class="btn" onclick="toast(\'Saved!\')">Save</button></div></div>'}
else if(uTab==='workshops'){const en=CU.workshops||[];c.innerHTML='<div class="tc"><div class="s2"><span>Your workshops ('+en.length+')</span></div>'+(en.length?en.map(w=>'<div class="ws-en"><div><div style="font-weight:500">'+w+'</div><div style="font-size:11px;color:var(--t2);margin-top:2px">Enrolled</div></div><span class="tag t-ac">Confirmed</span></div>').join(''):'<div class="empty">No workshops yet — browse upcoming below!</div>')+'</div><div class="tc"><div class="s2"><span>Upcoming workshops</span></div>'+workshops.map(w=>'<div class="ws-en"><div><div style="font-weight:500">'+w.name+'</div><div style="font-size:11px;color:var(--t2)">'+w.date+' · '+w.spots+' spots left</div></div><div style="display:flex;align-items:center;gap:8px"><span style="font-weight:500;color:var(--ac)">'+w.price+'</span>'+(en.includes(w.name)?'<span class="tag t-ac">Enrolled</span>':'<button class="btn btn-sm" onclick="enrollWS(\''+w.name+'\')">Enrol</button>')+'</div></div>').join('')+'</div>'}
else{const sv=CU.recipes||[];c.innerHTML='<div class="tc"><div class="s2"><span>Saved recipes ('+sv.length+')</span></div>'+(sv.length?sv.map(r=>'<div class="sr"><div style="font-weight:500">'+r+'</div><div style="font-size:11px;color:var(--t2);margin-top:4px">In your collection</div></div>').join(''):'<div class="empty">No saved recipes yet — explore the app to save recipes!</div>')+'</div>'}}
function enrollWS(n){if(!CU.workshops)CU.workshops=[];if(!CU.workshops.includes(n)){CU.workshops.push(n);toast('Enrolled in '+n+'!');renderUser()}else{toast('Already enrolled!')}}
