function rUL(q){const f=q.toLowerCase();const s=document.getElementById('uf').value;const ls=adUsers.filter(u=>{if(f&&!u.name.toLowerCase().includes(f)&&!u.email.toLowerCase().includes(f)&&!(u.notes||'').toLowerCase().includes(f))return false;if(s==='active'||s==='suspended'||s==='banned'){if(u.status!==s)return false}else if(s==='Premium'||s==='Free'){if(u.plan!==s)return false}return true});const el=document.getElementById('aul');if(!el)return;el.innerHTML=ls.map(u=>{const i=adUsers.indexOf(u);const cc=u.cancellations>0?'color:var(--dg)':'color:var(--ac)';return'<div class="uc"><div class="uc-t"><div class="av" style="background:'+u.color+'22;color:'+u.color+'">'+u.avatar+'</div><div class="uc-i"><div class="uc-nm">'+u.name+'</div><div class="uc-em">'+u.email+'</div></div>'+stTag(u.status)+'<span class="tag '+(u.plan==='Premium'?'t-use':'t-ssn')+'">'+u.plan+'</span></div><div class="uc-s"><div class="uc-sv"><div class="v">'+u.joined.split(' ').slice(0,2).join(' ')+'</div><div class="l">Joined</div></div><div class="uc-sv"><div class="v">'+u.workshops+'</div><div class="l">Workshops</div></div><div class="uc-sv"><div class="v" style="'+cc+'">'+u.cancellations+'</div><div class="l">Cancellations</div></div><div class="uc-sv"><div class="v" style="color:var(--ac)">&pound;'+u.spent.toFixed(2)+'</div><div class="l">Total spent</div></div></div><div class="uc-n"><textarea placeholder="Notes..." oninput="adUsers['+i+'].notes=this.value">'+u.notes+'</textarea></div><div style="display:flex;gap:6px;justify-content:flex-end;margin-top:8px">'+stBtns(u.status,i)+'</div></div>'}).join('')}

